<?php ao_schema_ensure_v1200(); $offers=[]; try{$offers=db()->query('SELECT o.*, l.title, l.domain_name FROM marketplace_offers o LEFT JOIN marketplace_listings l ON l.id=o.listing_id ORDER BY o.id DESC LIMIT 200')->fetchAll();}catch(Throwable $e){} $flash=get_flash(); ?>
<?php if($flash): ?><div class="ao-alert <?= e($flash['type']) ?>"><?= e($flash['message']) ?></div><?php endif; ?>
<div class="ao-page-head"><div><h2>Marketplace Teklifleri</h2><p>Teklif, karşı teklif, kabul ve red işlemleri.</p></div><a class="ao-btn soft" href="<?= url('admin/marketplace') ?>">İlanlar</a></div>
<div class="ao-card"><table class="ao-table"><thead><tr><th>İlan</th><th>Teklif Veren</th><th>Tutar</th><th>Durum</th><th>Karşı Teklif / Not</th><th>İşlem</th></tr></thead><tbody><?php foreach($offers as $o): ?><tr><td><b><?= e($o['domain_name'] ?: $o['title']) ?></b><br><small>#<?= (int)$o['listing_id'] ?></small></td><td><?= e($o['name'] ?: '-') ?><br><small><?= e($o['email'] ?: '') ?></small></td><td><?= number_format((float)$o['offer_amount'],2,',','.') ?> <?= e($o['currency']) ?></td><td><?= e($o['status']) ?></td><td><?= $o['counter_amount'] ? number_format((float)$o['counter_amount'],2,',','.') : '-' ?><br><small><?= e($o['admin_note'] ?? '') ?></small></td><td><form method="post" action="<?= url('admin/marketplace/offer-update') ?>" class="ao-inline-action"><?= csrf_field() ?><input type="hidden" name="id" value="<?= (int)$o['id'] ?>"><select name="status"><option value="pending">Beklemede</option><option value="accepted">Kabul</option><option value="rejected">Red</option><option value="countered">Karşı Teklif</option></select><input name="counter_amount" placeholder="Karşı teklif"><input name="admin_note" placeholder="Not"><button class="ao-mini-btn">Kaydet</button></form></td></tr><?php endforeach; if(!$offers): ?><tr><td colspan="6">Teklif yok.</td></tr><?php endif; ?></tbody></table></div>
